from flask import Flask, request, redirect, session, url_for
import requests
import os
import secrets
import urllib.parse

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', secrets.token_hex(16))

# OAuth configuration
CLIENT_ID = os.environ.get('OAUTH_CLIENT_ID')
CLIENT_SECRET = os.environ.get('OAUTH_CLIENT_SECRET')
AUTHORIZATION_SERVER = os.environ.get('OAUTH_AUTHORIZATION_SERVER')
TOKEN_SERVER = os.environ.get('OAUTH_TOKEN_SERVER')
REDIRECT_URI = os.environ.get('OAUTH_REDIRECT_URI')

@app.route('/login')
def login():
    # Generate secure state parameter
    state = secrets.token_urlsafe(32)
    session['oauth_state'] = state
    
    # Build authorization URL
    params = {
        'response_type': 'code',
        'client_id': CLIENT_ID,
        'redirect_uri': REDIRECT_URI,
        'state': state,
        'scope': 'openid profile email'
    }
    
    auth_url = f"{AUTHORIZATION_SERVER}?{urllib.parse.urlencode(params)}"
    return redirect(auth_url)

@app.route('/callback')
def callback():
    # Validate state parameter
    if 'oauth_state' not in session:
        return "Invalid state parameter", 400
    
    provided_state = request.args.get('state')
    if provided_state != session['oauth_state']:
        return "Invalid state parameter", 400
    
    # Get authorization code
    code = request.args.get('code')
    if not code:
        return "Authorization code not provided", 400
    
    # Exchange code for access token
    token_url = TOKEN_SERVER
    token_data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': REDIRECT_URI,
        'client_id': CLIENT_ID,
        'client_secret': CLIENT_SECRET
    }
    
    response = requests.post(token_url, data=token_data)
    
    if response.status_code != 200:
        return "Failed to obtain access token", 400
    
    token_info = response.json()
    
    # Store access token in session
    session['access_token'] = token_info.get('access_token')
    
    # Clear state parameter
    session.pop('oauth_state', None)
    
    return redirect(url_for('dashboard'))

@app.route('/dashboard')
def dashboard():
    if 'access_token' not in session:
        return redirect(url_for('login'))
    
    return "Logged in successfully!"

if __name__ == '__main__':
    app.run(debug=False)